import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const quizzesPath = path.join(__dirname, 'quizzes.json');
let quizzes = JSON.parse(fs.readFileSync(quizzesPath, 'utf8'));

const NEW_QUESTIONS = {
6: [
  {"question":"Set-associative cache 4-way berarti setiap set dapat menampung...","options":["1 cache line","2 cache line","4 cache line","8 cache line"],"answer":2,"difficulty":2,"explanation":"4-way set associative = setiap set punya 4 slot (ways). Satu blok memori bisa dipetakan ke salah satu dari 4 posisi dalam set yang sesuai, fleksibilitas lebih dari direct-mapped tanpa overhead penuh fully associative."},
  {"question":"Pada direct-mapped cache dengan 8 set, blok memori nomor 21 dipetakan ke set nomor...","options":["21","5","3","2"],"answer":1,"difficulty":2,"explanation":"Index set = nomor blok MOD jumlah set = 21 MOD 8 = 5. Direct-mapped menggunakan modulo — blok 5, 13, 21, 29 semuanya bersaing di set yang sama (conflict miss)."},
  {"question":"Write-allocate policy pada cache write-miss berarti...","options":["Data langsung ditulis ke memori utama tanpa mengubah cache","Blok dari memori di-load dulu ke cache baru kemudian ditulis","Write diabaikan jika cache penuh","Data ditulis ke register sementara"],"answer":1,"difficulty":2,"explanation":"Write-allocate (fetch-on-write): saat write-miss, blok yang akan ditulis di-fetch dulu dari memori ke cache, kemudian penulisan dilakukan di cache. Biasanya dipasangkan dengan write-back policy."},
  {"question":"Victim cache ditempatkan antara L1 dan L2 dengan tujuan...","options":["Menyimpan instruksi yang sudah dieksekusi","Menampung blok yang baru saja di-evict dari L1 sebelum ke L2","Menyimpan data yang sering ditulis ke disk","Cache khusus untuk operasi floating point"],"answer":1,"difficulty":3,"explanation":"Victim cache (Jouppi 1990): small fully-associative cache antara L1 dan L2. Blok yang di-evict dari L1 masuk ke victim cache — jika segera diakses lagi (miss di L1 tapi hit di victim cache) latency jauh lebih rendah dari L2 miss."},
  {"question":"Cache thrashing terjadi ketika...","options":["Cache terlalu besar untuk working set program","Program terus-menerus mengakses blok yang saling menggusur di set yang sama","CPU mengakses cache lebih cepat dari spesifikasi","L1 dan L2 cache kehilangan sinkronisasi"],"answer":1,"difficulty":3,"explanation":"Thrashing: dalam direct-mapped atau N-way dengan sedikit ways, jika program mengakses blok yang memetakan ke set sama secara bergantian, mereka terus saling menggusur (conflict miss terus-menerus). Solusi: meningkatkan associativity atau mengubah layout data."},
  {"question":"Inclusive cache policy berarti...","options":["L1 dan L2 tidak boleh menyimpan blok yang sama","L2 hanya menyimpan blok yang tidak ada di L1","Semua blok di L1 pasti ada salinannya di L2","L1 selalu lebih besar dari L2"],"answer":2,"difficulty":3,"explanation":"Inclusive: semua data di L1 dijamin ada di L2. Keuntungan: coherency mudah (invalidate di L2 cukup). Kerugian: kapasitas L2 terbuang untuk duplikasi. Exclusive policy sebaliknya — blok hanya ada di satu level."},
  {"question":"AMAT = Hit Time + Miss Rate × Miss Penalty. Jika hit time 4ns, miss rate 10%, miss penalty 100ns, maka AMAT adalah...","options":["104ns","14ns","40ns","4.1ns"],"answer":1,"difficulty":2,"explanation":"AMAT = 4 + (0.10 × 100) = 4 + 10 = 14ns. Miss penalty 100ns dengan miss rate 10% memberikan kontribusi 10ns, mendominasi hit time 4ns. Formula ini digunakan untuk mengevaluasi efektivitas desain cache."},
  {"question":"Tag field pada alamat cache digunakan untuk...","options":["Menentukan set mana yang dituju","Menentukan byte mana di dalam blok","Memverifikasi apakah blok di cache memang yang dicari","Menentukan algoritma replacement yang dipakai"],"answer":2,"difficulty":2,"explanation":"Alamat dibagi: [Tag | Index | Offset]. Tag dibandingkan dengan tag tersimpan di cache line untuk verifikasi hit/miss. Index menentukan set. Offset menentukan byte dalam blok. Tag check terjadi setiap akses."},
  {"question":"False sharing dalam multiprocessor cache terjadi ketika...","options":["Dua prosesor mengakses variabel yang persis sama","Dua prosesor mengakses variabel berbeda yang berada dalam cache line yang sama","L1 cache tidak konsisten dengan L2 cache","Cache overflow karena data terlalu besar"],"answer":1,"difficulty":3,"explanation":"False sharing: prosesor A dan B mengakses variabel berbeda (X dan Y) dalam satu cache line. Saat A menulis X, cache line di-invalidate di B — B harus fetch ulang padahal Y tidak berubah. Overhead signifikan di program paralel."},
  {"question":"Dirty bit pada write-back cache digunakan untuk...","options":["Menandai blok yang sedang dalam proses prefetch","Menandai blok yang dimodifikasi di cache tapi belum ditulis ke memori","Mendeteksi error parity dalam cache","Menandai cache line yang sudah kadaluarsa"],"answer":1,"difficulty":2,"explanation":"Dirty bit = 1 berarti cache line telah dimodifikasi CPU tapi memori utama belum diupdate. Saat blok di-evict: dirty=1 → write-back ke memori dulu; dirty=0 → buang saja (memori sudah up-to-date)."},
  {"question":"3C model of cache misses terdiri dari...","options":["Cold miss, Conflict miss, Capacity miss","Core miss, Clock miss, Cache miss","Cold miss, Coherence miss, Computation miss","Compulsory miss, CPU miss, Clock miss"],"answer":0,"difficulty":2,"explanation":"3C (Hennessy & Patterson): (1) Compulsory/Cold — akses pertama ke blok, tak bisa dihindari; (2) Capacity — working set > ukuran cache; (3) Conflict — blok saling tabrakan di set sama. Multiprocessor menambah (4) Coherence miss."},
  {"question":"Pada sistem dengan physical address 32-bit, cache 16KB direct-mapped, block size 64B, berapa bit untuk field Index?","options":["6 bit","8 bit","10 bit","4 bit"],"answer":1,"difficulty":3,"explanation":"Jumlah set = 16KB / 64B = 256 set. Bit index = log2(256) = 8 bit. Bit offset = log2(64) = 6 bit. Tag = 32 - 8 - 6 = 18 bit. Pembagian bit ini fundamental untuk desain dan analisis cache."},
  {"question":"Non-temporal store (instruksi MOVNT pada x86) melewati cache karena...","options":["Data tersebut bukan instruksi program","Data hanya ditulis sekali dan tidak akan segera diakses lagi","Operasi tersebut memerlukan akses DMA","Non-temporal store hanya untuk data GPU"],"answer":1,"difficulty":3,"explanation":"Non-temporal store menulis langsung ke memori tanpa mengisi cache. Berguna untuk streaming data besar (video, memcpy) yang tidak akan diakses ulang segera — memasukkan ke cache justru mengotori cache dengan data tidak berguna (cache pollution)."},
  {"question":"Perbedaan I-cache dan D-cache pada Harvard Architecture adalah...","options":["I-cache selalu lebih besar dari D-cache","Keduanya terpisah sehingga fetch instruksi dan akses data bisa terjadi simultan","D-cache hanya untuk operasi write","I-cache tidak menggunakan locality of reference"],"answer":1,"difficulty":2,"explanation":"Harvard architecture memisahkan I-cache dan D-cache agar pipeline dapat fetch instruksi (dari I-cache) sekaligus membaca/menulis data (dari D-cache) dalam cycle yang sama, menghilangkan structural hazard akses memori."},
  {"question":"Multi-level cache L1, L2, L3 dirancang berdasarkan prinsip...","options":["L1 harus menyimpan seluruh program","Ada trade-off kecepatan vs kapasitas — L1 kecil-cepat, L3 besar-lambat","Setiap core wajib punya cache sendiri secara hukum hardware","L3 harus di luar chip CPU"],"answer":1,"difficulty":2,"explanation":"Memory hierarchy: semakin dekat CPU semakin cepat tapi mahal per-bit. L1 (~4 cycle, 32-64KB), L2 (~12 cycle, 256KB-1MB), L3 (~30-40 cycle, 8-64MB). Tujuan: mayoritas akses terpenuhi dari cache cepat, meminimalkan akses DRAM (~200 cycle)."},
  {"question":"Hardware prefetcher memprediksi blok cache yang dibutuhkan berdasarkan...","options":["Prediksi AI dari sistem operasi","Pola akses memori yang terdeteksi seperti stride pattern","Instruksi PREFETCH eksplisit dari programmer saja","Ukuran program yang sedang berjalan"],"answer":1,"difficulty":3,"explanation":"Hardware prefetcher menganalisis pola: (1) Stream prefetcher: akses sequential (array traversal); (2) Stride prefetcher: pola jarak tetap (array 2D); (3) Pointer/indirect prefetcher: linked list. Prefetch tepat mengurangi miss rate secara dramatis tanpa intervensi programmer."},
  {"question":"Algoritma penggantian cache Optimal (Belady's) tidak bisa diimplementasikan di hardware nyata karena...","options":["Terlalu mahal secara hardware","Membutuhkan pengetahuan tentang akses memori di masa depan","Tidak bekerja pada direct-mapped cache","Membutuhkan cache yang sangat besar"],"answer":1,"difficulty":3,"explanation":"Optimal algorithm (Belady 1966) mengganti blok yang tidak akan diakses paling lama di masa depan — memberikan miss rate teoritis minimum. Tidak implementable karena CPU tidak bisa memprediksi masa depan. Digunakan sebagai benchmark pembanding untuk algoritma praktis (LRU, FIFO, Random)."},
  {"question":"Pseudo-LRU (PLRU) digunakan sebagai pengganti LRU murni pada cache dengan associativity tinggi karena...","options":["PLRU lebih akurat dari LRU","LRU murni membutuhkan hardware counter per cache line yang terlalu mahal","PLRU lebih cepat membaca data","LRU tidak bekerja pada cache dengan lebih dari 4 way"],"answer":1,"difficulty":3,"explanation":"LRU murni pada N-way cache membutuhkan log2(N!) bit per set untuk melacak urutan akses semua N ways — sangat mahal untuk 8-way atau 16-way. PLRU menggunakan bit tree (N-1 bit per set) untuk aproximasi LRU yang cukup baik dengan hardware minimal."},
  {"question":"Fenomena cold start miss (compulsory miss) pada cache tidak dapat dihilangkan sepenuhnya karena...","options":["Cache selalu penuh saat program mulai","Setiap blok data harus diakses setidaknya sekali pertama kali dan pasti miss","Program tidak bisa memprediksi data yang dibutuhkan","OS tidak mengizinkan prefetch sebelum program mulai"],"answer":1,"difficulty":2,"explanation":"Compulsory/cold miss: akses pertama kali ke setiap blok pasti miss karena blok belum pernah di-load ke cache. Tidak bisa dihilangkan — hanya bisa dikurangi dengan prefetching (membawa blok sebelum dibutuhkan) atau larger cache line (lebih banyak data per miss)."},
  {"question":"Write-back cache meningkatkan performa dibanding write-through karena...","options":["Write-back tidak memerlukan dirty bit","Write ke memori utama dilakukan sekaligus saat eviction bukan setiap write","Write-back cache lebih besar kapasitasnya","Write-through lebih lambat karena harus membaca sebelum menulis"],"answer":1,"difficulty":2,"explanation":"Write-through: setiap write ke cache juga langsung menulis ke memori — bandwidth memori tinggi. Write-back: tulis hanya ke cache, ke memori hanya saat eviction — mengurangi traffic memori drastis. Jika blok ditulis 100x sebelum di-evict, write-back hanya 1 kali ke memori vs write-through 100 kali."},
],
7: [
  {"question":"SRAM menggunakan flip-flop untuk menyimpan data. Konsekuensinya adalah...","options":["SRAM perlu refresh periodik seperti DRAM","SRAM lebih cepat tapi membutuhkan lebih banyak transistor per bit","SRAM lebih murah per bit dari DRAM","SRAM tidak bisa digunakan sebagai cache"],"answer":1,"difficulty":2,"explanation":"SRAM: 6 transistor per bit (flip-flop bistable) → lebih besar, mahal, tapi tidak butuh refresh dan akses sangat cepat (~1ns). DRAM: 1 transistor + 1 kapasitor per bit → padat, murah, tapi butuh refresh setiap ~64ms karena kapasitor bocor."},
  {"question":"Burst mode SDRAM (Synchronous DRAM) berarti...","options":["SDRAM bisa membaca dan menulis sekaligus","Setelah akses pertama, SDRAM menghasilkan data berikutnya secara sequential dengan kecepatan penuh","SDRAM menggunakan clock burst untuk meningkatkan voltage","Mode di mana seluruh memory diakses sekaligus"],"answer":1,"difficulty":2,"explanation":"Burst mode: CPU mengakses alamat awal, SDRAM secara otomatis menyediakan N byte berikutnya sesuai cache line size tanpa perlu address baru. Sangat efisien untuk sequential access (fetch instruksi, DMA). SDRAM sinkron dengan clock CPU sehingga timing lebih presisi dari DRAM asinkron."},
  {"question":"ECC (Error Correcting Code) memory menggunakan kode Hamming untuk...","options":["Mengenkripsi data agar aman dari serangan","Mendeteksi dan memperbaiki single-bit error, mendeteksi double-bit error","Mengompresi data agar muat lebih banyak","Mempercepat akses memori dengan prediksi"],"answer":1,"difficulty":2,"explanation":"ECC dengan Hamming code: menambah bit paritas redundan (untuk 64-bit data perlu 8 bit parity = 72-bit ECC). Single Error Correction, Double Error Detection (SECDED). Digunakan di server dan workstation kritis — single bit flip dari cosmic ray bisa menyebabkan crash atau korupsi data tanpa ECC."},
  {"question":"DDR5 RAM memiliki keunggulan dibanding DDR4 dalam hal...","options":["Konsumsi daya yang lebih tinggi untuk kecepatan lebih","Bandwidth lebih tinggi dan voltase operasi lebih rendah (1.1V vs 1.2V)","Kompatibilitas penuh dengan slot DDR4","Kapasitas per chip lebih rendah tapi kecepatan lebih tinggi"],"answer":1,"difficulty":2,"explanation":"DDR5 vs DDR4: bandwidth 2x lipat (DDR5-4800 vs DDR4-3200), voltase turun dari 1.2V ke 1.1V (hemat daya), kapasitas per DIMM meningkat (up to 128GB), dan manajemen power pindah ke modul (on-die ECC). Tidak backward compatible dengan slot DDR4."},
  {"question":"Interleaved memory organisation membagi memori ke beberapa bank untuk...","options":["Meningkatkan kapasitas total memori","Memungkinkan akses paralel ke bank berbeda, meningkatkan throughput efektif","Mengurangi biaya produksi memori","Menyederhanakan rangkaian address decoder"],"answer":1,"difficulty":2,"explanation":"Interleaving: alamat memori didistribusikan ke N bank secara round-robin (alamat 0→bank0, 1→bank1, ..., N→bank0). CPU bisa mulai akses bank1 sementara bank0 masih dalam latency recovery, sehingga throughput efektif meningkat N kali untuk sequential access."},
  {"question":"NAND Flash berbeda dari NOR Flash dalam hal...","options":["NAND lebih cepat untuk random read, NOR lebih cepat untuk sequential","NOR lebih lambat tapi lebih padat, NAND lebih cepat tapi lebih mahal","NAND lebih padat dan lebih cepat untuk sequential write, NOR lebih cepat untuk random read","NAND tidak bisa diprogram ulang sedangkan NOR bisa"],"answer":2,"difficulty":3,"explanation":"NAND: sel disusun seri (padat, murah, cocok mass storage), akses byte tidak langsung, harus baca/tulis per page (~4KB). NOR: sel paralel, bisa execute-in-place (XIP), direct byte access, digunakan untuk firmware/BIOS. SSD dan USB drive menggunakan NAND."},
  {"question":"Row Hammer attack pada DRAM mengeksploitasi...","options":["Kelemahan enkripsi dalam modul memori","Efek fisik di mana akses berulang ke satu row bisa membalik bit di row yang berdekatan","Buffer overflow dalam driver memori","Kelemahan protokol refresh DRAM"],"answer":1,"difficulty":3,"explanation":"Row Hammer (2014): mengakses (hammer) satu DRAM row berulang-ulang dalam waktu singkat menyebabkan kebocoran muatan yang cukup untuk membalik bit di row tetangga. Eksploitasi ini bisa digunakan untuk privilege escalation. Mitigasi: Target Row Refresh (TRR), ECC, dan peningkatan refresh rate."},
  {"question":"Perbedaan antara byte addressing dan word addressing pada memori adalah...","options":["Byte addressing selalu lebih lambat dari word addressing","Pada byte addressing setiap lokasi memori berisi 1 byte, word addressing setiap lokasi berisi 1 word (biasanya 4 byte)","Word addressing tidak kompatibel dengan CPU modern","Byte addressing membutuhkan lebih banyak address line"],"answer":1,"difficulty":2,"explanation":"Byte addressing: setiap alamat menunjuk 1 byte — x86, ARM, dan hampir semua CPU modern menggunakan ini. Word addressing: setiap alamat menunjuk 1 word (32-bit) — beberapa DSP dan RISC awal. Implikasi: byte addressing membutuhkan 2 bit lebih banyak untuk mengalamati memori yang sama dibanding 32-bit word addressing."},
  {"question":"Memory-mapped I/O vs Port-mapped I/O (isolated I/O): perbedaan utamanya adalah...","options":["Memory-mapped I/O hanya untuk memori eksternal","Memory-mapped I/O menggunakan ruang alamat memori untuk device register, port-mapped menggunakan ruang alamat I/O terpisah","Port-mapped I/O tidak memerlukan bus","Memory-mapped I/O lebih lambat karena harus melalui cache"],"answer":1,"difficulty":2,"explanation":"Memory-mapped I/O: device register dipetakan ke ruang alamat memori — bisa diakses dengan instruksi LOAD/STORE biasa, lebih fleksibel, digunakan ARM dan kebanyakan RISC. Port-mapped: instruksi khusus IN/OUT, ruang alamat terpisah (64KB pada x86), proteksi lebih mudah."},
  {"question":"NVDIMM (Non-Volatile DIMM) menggabungkan DRAM dan NAND Flash untuk...","options":["Menggandakan kapasitas memori tanpa menambah slot","Mempertahankan data saat power loss sambil tetap memberikan kecepatan akses mendekati DRAM","Menggantikan SSD dalam sistem server","Memberikan enkripsi hardware untuk data sensitif"],"answer":1,"difficulty":3,"explanation":"NVDIMM: DRAM untuk akses kecepatan tinggi + NAND Flash sebagai backup + supercapacitor. Saat power loss, supercapacitor menyuplai power cukup lama untuk mentransfer seluruh DRAM ke NAND. Saat power kembali, data di-restore ke DRAM. Digunakan untuk persistent memory di server kelas enterprise."},
  {"question":"Fenomena 'memory wall' (Wulf & McKee 1995) menggambarkan masalah...","options":["Kapasitas memori tidak bisa ditingkatkan lagi","Kesenjangan kecepatan antara CPU dan DRAM yang terus melebar setiap tahun","Memori tidak bisa diakses lebih dari satu kali per clock","DRAM tidak bisa berfungsi di suhu tinggi"],"answer":1,"difficulty":3,"explanation":"Memory wall: CPU speed meningkat ~55% per tahun (era 1990-an) sedangkan DRAM latency hanya turun ~7% per tahun. Gap ini terus melebar — CPU modern bisa mengeksekusi ratusan instruksi dalam waktu yang dibutuhkan untuk satu DRAM access. Cache hierarchy adalah respons utama terhadap memory wall problem."},
  {"question":"Timing parameter CL16-18-18-38 pada spesifikasi RAM DDR4 merujuk pada...","options":["Kecepatan MHz dari masing-masing pin RAM","CAS Latency, RAS to CAS Delay, RAS Precharge, dan Row Active Time dalam clock cycles","Jumlah chip dalam satu modul DIMM","Voltase operasi minimum dan maksimum"],"answer":1,"difficulty":3,"explanation":"Timing DDR4: CL (CAS Latency) = clock dari RAS#→data; tRCD (RAS to CAS Delay) = row activation ke column access; tRP (RAS Precharge) = precharge row; tRAS (Row Active Time) = row harus aktif minimum. Angka lebih kecil = lebih cepat. CL16 @ DDR4-3200 = 16/3200MHz×2 = ~10ns latency aktual."},
  {"question":"Kenapa DRAM modern menggunakan double data rate (DDR) alih-alih single data rate?","options":["DDR mengkonsumsi daya setengah dari SDR","DDR mentransfer data pada rising DAN falling edge clock, menggandakan bandwidth tanpa menaikkan frekuensi clock","DDR tidak memerlukan refresh periodik","DDR memiliki kapasitas 2x lebih besar"],"answer":1,"difficulty":2,"explanation":"DDR memanfaatkan kedua tepi (edge) sinyal clock — transfer di rising AND falling edge. DDR4-3200: clock fisik 1600 MHz, tapi 3200 MT/s karena dua transfer per cycle. Bandwidth = 3200 MT/s × 8 bytes (64-bit bus) = 25.6 GB/s per channel. Ini 2x bandwidth dari SDR dengan clock sama."},
  {"question":"Apa fungsi Memory Controller yang terintegrasi langsung di CPU (on-die) dibanding External Memory Controller?","options":["Menambah kapasitas memori yang bisa digunakan","Mengurangi latency akses memori dengan menghilangkan hop melalui northbridge","Memungkinkan penggunaan jenis RAM yang berbeda","Meningkatkan voltase untuk stabilitas"],"answer":1,"difficulty":2,"explanation":"Integrasi memory controller ke dalam CPU die (AMD sejak Athlon 64 2003, Intel sejak Nehalem 2008) menghilangkan bottleneck northbridge. Latensi memori turun signifikan (dari ~80ns menjadi ~50ns) karena tidak perlu traversal FSB (Front Side Bus) eksternal yang menjadi bottleneck bandwidth."},
  {"question":"Storage class memory (SCM) seperti Intel Optane mengisi posisi...","options":["Menggantikan L3 cache di dalam CPU","Di antara DRAM dan SSD dalam hierarki memori, dengan latensi dan persistensi di antara keduanya","Menggantikan NAND Flash sepenuhnya","Di antara L1 dan L2 cache"],"answer":1,"difficulty":3,"explanation":"SCM (menggunakan 3D XPoint/Phase Change Memory): latency ~300ns (vs DRAM ~80ns, SSD ~100μs), byte-addressable seperti DRAM, non-volatile seperti SSD. Mengisi gap besar dalam memory hierarchy. Intel Optane DIMM bisa digunakan sebagai persistent memory atau memory extender untuk workload besar."},
  {"question":"Kenapa kapasitas memori yang bisa diaddress CPU 32-bit terbatas 4GB?","options":["Standar industri membatasi 4GB untuk kompatibilitas","Bus alamat 32-bit hanya bisa merepresentasikan 2^32 = 4.294.967.296 alamat unik","Sistem operasi 32-bit tidak mendukung lebih dari 4GB","Kapasitor DRAM tidak cukup besar untuk 4GB+"],"answer":1,"difficulty":2,"explanation":"Address space = 2^(jumlah bit alamat). CPU 32-bit: 2^32 = ~4.29 miliar alamat unik. Jika setiap alamat menunjuk 1 byte: maksimum 4GB addressable. PAE (Physical Address Extension) bisa memperluas ini ke 64GB dengan trik page table, tapi tiap proses tetap terbatas 4GB virtual address space."},
  {"question":"Parity bit pada memori dapat mendeteksi error tapi tidak bisa memperbaikinya karena...","options":["Parity bit hanya cukup untuk mengetahui ada error tapi tidak lokasi bit yang salah","Parity bit tidak bekerja pada multi-bit error","Parity bit hanya untuk deteksi error di bus, bukan di chip memori","Parity membutuhkan clock sinkronisasi tambahan"],"answer":0,"difficulty":2,"explanation":"Single parity bit memberikan info 'jumlah bit '1' genap atau ganjil' — hanya bisa membedakan 'ada error' atau 'tidak ada error', tidak bisa menentukan bit mana yang flip untuk dikoreksi. ECC menambahkan cukup bit redundan (multiple parity bit dengan posisi berbeda) sehingga lokasi error bisa dihitung dan dikoreksi."},
  {"question":"LPDDR (Low Power DDR) digunakan di smartphone/laptop tipis dibanding DDR biasa karena...","options":["LPDDR memiliki kapasitas lebih besar","LPDDR beroperasi pada voltase lebih rendah (0.6-1.1V vs 1.2V) dan memiliki fitur power management canggih","LPDDR lebih cepat dari DDR dalam segala kondisi","LPDDR tidak memerlukan refresh periodik"],"answer":1,"difficulty":2,"explanation":"LPDDR (Low Power Double Data Rate): dirancang untuk mobile. Voltase lebih rendah = konsumsi daya lebih kecil. Fitur power management: partial array refresh (hanya refresh area yang aktif), deep power down mode, dll. Trade-off: biasanya di-solder langsung ke PCB (tidak upgradeable) dan bandwidth sedikit di bawah standar DDR."},
  {"question":"Apa yang dimaksud dengan memory rank pada modul DIMM?","options":["Kapasitas total modul dalam GB","Set chip memori yang secara kolektif menyediakan lebar bus data 64-bit","Kecepatan maksimum modul dalam MHz","Jumlah layer PCB dalam modul"],"answer":1,"difficulty":3,"explanation":"Memory rank: sekelompok chip DRAM yang bekerja bersama menyediakan 64-bit data (atau 72-bit untuk ECC). DIMM single-rank: semua chip di satu sisi aktif bersamaan. Dual-rank: dua kelompok chip, hanya satu aktif per akses. Server bisa menggunakan quad-rank RDIMM untuk kapasitas maksimal. Lebih banyak rank = capacity tinggi tapi timing sedikit lebih lambat."},
  {"question":"Teknik 3D stacking (HBM - High Bandwidth Memory) menumpuk chip DRAM vertikal untuk...","options":["Mengurangi kapasitas agar lebih murah","Mendekatkan memori ke GPU die sehingga bandwidth sangat tinggi dan latensi rendah via Through-Silicon Via (TSV)","Meningkatkan voltase operasi untuk kecepatan lebih","Menggantikan kebutuhan cache pada GPU"],"answer":1,"difficulty":3,"explanation":"HBM (AMD Fury, NVIDIA A100): chip DRAM ditumpuk vertikal dan dihubungkan ke GPU die via silicon interposer menggunakan Through-Silicon Via (TSV). Bus sangat lebar (1024-bit per stack vs 256-bit GDDR6). HBM4 mencapai >3.6 TB/s bandwidth — solusi untuk memory bandwidth bottleneck pada AI workload."},
],
8: [
  {"question":"Addressing mode 'register indirect' berbeda dari 'register direct' karena...","options":["Register indirect menggunakan dua register sekaligus","Register indirect menggunakan nilai dalam register sebagai alamat memori, bukan sebagai data langsung","Register indirect lebih lambat karena perlu decode tambahan","Register indirect hanya tersedia pada CISC architecture"],"answer":1,"difficulty":2,"explanation":"Register direct: operand adalah nilai dalam register (mov R1, R2 → R1 = nilai R2). Register indirect: operand adalah data di memori yang alamatnya ada dalam register (mov R1, [R2] → R1 = memori[R2]). Indirect memungkinkan pointer dan array access dengan satu instruksi."},
  {"question":"Relative addressing mode pada branch instruction menggunakan...","options":["Alamat absolut dari target instruksi","Offset (signed) relatif terhadap Program Counter saat ini","Nilai dari stack pointer","Alamat awal segment kode"],"answer":1,"difficulty":2,"explanation":"PC-relative addressing: target = PC + offset. Offset disimpan dalam instruksi (biasanya 8-26 bit signed). Keuntungan: kode position-independent (bisa di-load di alamat mana saja tanpa relinkasi), instruksi lebih pendek karena offset jauh lebih kecil dari alamat absolut. Digunakan oleh hampir semua ISA modern untuk branch."},
  {"question":"Instruksi CALL pada x86 secara otomatis...","options":["Menyimpan semua register ke stack","Menyimpan return address (PC berikutnya) ke stack lalu jump ke fungsi yang dipanggil","Mengalokasikan frame baru di heap","Menginisialisasi base pointer untuk fungsi baru"],"answer":1,"difficulty":2,"explanation":"CALL: (1) PUSH EIP+instruksi_size ke stack (return address), (2) JMP ke alamat fungsi. RET kemudian: POP alamat dari stack ke EIP. Mekanisme ini memungkinkan nested dan recursive call. Stack frame lengkap (local variables, saved registers) diurus oleh function prologue/epilogue, bukan instruksi CALL itu sendiri."},
  {"question":"Perbedaan zero-address (stack) machine dengan three-address machine adalah...","options":["Stack machine lebih cepat karena tidak perlu decode operand","Stack machine mengambil operand implisit dari stack, three-address machine menentukan semua operand secara eksplisit","Three-address machine hanya tersedia di superkomputer","Stack machine tidak bisa melakukan operasi aritmatika"],"answer":1,"difficulty":2,"explanation":"Zero-address (stack): semua operasi pada TOS (Top of Stack). PUSH A; PUSH B; ADD; POP C. Three-address: ADD C, A, B — sumber dan tujuan eksplisit, compiler bisa optimasi lebih bebas. RISC modern menggunakan three-address (register-register). Java bytecode menggunakan stack machine."},
  {"question":"Instruksi format RISC biasanya fixed-length (32-bit) sedangkan CISC (x86) variable-length. Keuntungan fixed-length untuk pipeline adalah...","options":["Fixed-length lebih mudah dikompresi","Instruksi fetch dan decode bisa dilakukan dalam satu cycle karena panjang pasti, menyederhanakan pipeline","Fixed-length lebih hemat memori","Variable-length tidak bisa dieksekusi secara out-of-order"],"answer":1,"difficulty":2,"explanation":"Fixed-length: decoder tahu pasti batas setiap instruksi sebelum di-decode, fetch tepat 32-bit = satu instruksi, decode paralel mudah. Variable-length (x86): decoder harus scan prefix untuk tentukan panjang, bisa 1-15 byte, boundary instruction sulit ditentukan — x86 CPU modern menghabiskan area chip signifikan hanya untuk instruction boundary detection."},
  {"question":"Little-endian vs big-endian dalam konteks ISA: x86 menggunakan little-endian yang berarti...","options":["Byte pertama dalam memori adalah yang paling signifikan","Byte dengan nilai paling kecil disimpan lebih dulu","Byte paling tidak signifikan (LSB) disimpan di alamat memori terkecil","Data disimpan dari kanan ke kiri dalam register"],"answer":2,"difficulty":2,"explanation":"Little-endian (Intel x86, ARM): byte terendah (LSB) di alamat terendah. Nilai 0x12345678 disimpan sebagai: [0x78][0x56][0x34][0x12]. Big-endian (network byte order, SPARC lama): MSB di alamat terendah. Penting saat: network communication, file format, multi-platform data exchange."},
  {"question":"Privilege levels (Ring 0-3) pada x86 ISA digunakan untuk...","options":["Menentukan kecepatan eksekusi instruksi","Memisahkan level kepercayaan: Ring 0 untuk kernel (akses penuh), Ring 3 untuk aplikasi user (akses terbatas)","Mengatur prioritas thread dalam multitasking","Menentukan ukuran maksimum program"],"answer":1,"difficulty":2,"explanation":"x86 protection rings: Ring 0 (kernel mode) — akses semua instruksi dan hardware, Ring 1-2 (jarang digunakan, driver), Ring 3 (user mode) — instruksi privileged dilarang, akses hardware via system call. Transisi Ring 3→Ring 0 hanya melalui INT, SYSCALL, atau exception — diverifikasi hardware, bukan bisa di-bypass software."},
  {"question":"Instruksi NOP (No Operation) sering digunakan dalam program untuk...","options":["Menginisialisasi register ke nilai nol","Pipeline alignment, delay slot filling, dan area placeholder untuk patching","Menandai akhir program","Reset semua flag kondisi ke 0"],"answer":1,"difficulty":2,"explanation":"NOP uses: (1) Delay slot padding (RISC tanpa interlocking): instruksi setelah branch dieksekusi selalu, NOP mengisi jika tidak ada instruksi berguna; (2) Pipeline alignment: menyelaraskan instruksi ke boundary tertentu untuk performa; (3) Code patching: ruang untuk instruksi yang akan diinsert kemudian; (4) Timing loop dalam embedded systems."},
  {"question":"System call (SYSCALL/INT 0x80) adalah mekanisme untuk...","options":["Memanggil fungsi dalam library eksternal","Meminta layanan dari kernel OS dengan aman, berpindah dari Ring 3 ke Ring 0 secara terkontrol","Reset CPU ke kondisi awal","Mengakses instruksi floating point"],"answer":1,"difficulty":2,"explanation":"System call: user program (Ring 3) tidak bisa langsung akses hardware. SYSCALL/INT 0x80 menyebabkan CPU berpindah ke Ring 0 (kernel), mengeksekusi handler spesifik berdasarkan syscall number dalam register, lalu kembali ke Ring 3. Semua akses file, network, memory allocation pada dasarnya melalui system call."},
  {"question":"SIMD instruction (Single Instruction Multiple Data) seperti SSE/AVX pada x86 berguna untuk...","options":["Mengeksekusi multiple thread secara bersamaan","Satu instruksi mengoperasikan multiple data element sekaligus dalam register lebar (128/256/512-bit)","Memberikan instruksi berbeda ke core berbeda","Meningkatkan frekuensi clock secara dinamis"],"answer":1,"difficulty":3,"explanation":"SIMD: SSE2 punya register 128-bit, bisa proses 4 float atau 2 double sekaligus. AVX2: 256-bit, 8 float atau 4 double. AVX-512: 512-bit, 16 float. Digunakan dalam: encoding video (H.264/H.265), machine learning inference, kriptografi, rendering grafis — speedup 4-16x dibanding scalar untuk compute-bound workload."},
  {"question":"Load-use hazard dalam pipeline RISC terjadi ketika...","options":["Instruksi LOAD dan STORE mengakses alamat yang sama","Instruksi setelah LOAD mencoba menggunakan hasil LOAD sebelum data tersedia dari memori","Dua instruksi LOAD dieksekusi bersamaan","Cache miss terjadi saat LOAD"],"answer":1,"difficulty":3,"explanation":"Load-use hazard: instruksi LOAD menulis hasil ke register setelah stage MEM (biasanya cycle ke-4). Instruksi berikutnya yang membaca register tersebut sudah di stage EX cycle ke-3 — terlalu awal. Forwarding tidak bisa membantu (data belum ada). Solusi: load-use stall (1 bubble) atau compiler reorder instruksi untuk fill slot."},
  {"question":"VLIW (Very Long Instruction Word) architecture memindahkan tanggung jawab instruction scheduling ke...","options":["Hardware branch predictor","Compiler saat compile time, bukan hardware saat runtime","Sistem operasi saat program loading","Programmer secara eksplisit dalam assembly"],"answer":1,"difficulty":3,"explanation":"VLIW: satu instruction word sangat panjang (misalnya 256-bit) berisi beberapa operasi independen yang dieksekusi paralel. Hardware tidak perlu hazard detection atau out-of-order — compiler sudah menjamin tidak ada dependency. Sederhana di hardware, sulit di compiler. Intel Itanium (EPIC) adalah contoh komersial yang kurang berhasil."},
  {"question":"Delayed branching pada RISC pipeline awal mengharuskan programmer atau compiler untuk...","options":["Menghindari penggunaan branch sama sekali","Menempatkan instruksi berguna di branch delay slot yang selalu dieksekusi setelah branch","Menambahkan NOP sebelum setiap branch","Menggunakan register khusus untuk menyimpan alamat target branch"],"answer":1,"difficulty":3,"explanation":"Delayed branch (MIPS awal, SPARC): instruksi tepat setelah branch (delay slot) selalu dieksekusi, terlepas branch diambil atau tidak. Compiler mengisi delay slot dengan instruksi yang berguna dalam semua kasus — jika tidak bisa, diisi NOP. Menyembunyikan 1-cycle branch penalty tanpa hardware branch predictor yang mahal."},
  {"question":"ISA register file dengan banyak register (32 register pada RISC) vs sedikit (8 register pada x86-32) memberikan keuntungan...","options":["Lebih banyak register berarti CPU lebih cepat secara keseluruhan","Lebih banyak register memungkinkan compiler menyimpan lebih banyak variabel lokal tanpa akses memori (register allocation lebih baik)","Register file besar mengurangi kebutuhan cache","32 register tidak cukup untuk program kompleks"],"answer":1,"difficulty":2,"explanation":"Register allocation: kompiler berusaha menjaga variabel yang sering digunakan di register (akses ~0 cycle) daripada di stack (akses ~4-200 cycle). Dengan 8 register (x86-32), variabel lebih sering spill ke memori. Dengan 32 register (RISC), lebih banyak variabel bisa di-register sepanjang fungsi — code lebih cepat."},
  {"question":"Memory ordering model 'Total Store Order' (TSO) pada x86 berarti...","options":["Semua akses memori berjalan secara serial tanpa reordering","Store dapat tertunda dalam store buffer tapi semua processor melihat semua store dalam urutan yang sama","Load selalu terjadi sebelum store dalam program yang sama","x86 tidak mengizinkan out-of-order memory access"],"answer":1,"difficulty":3,"explanation":"x86 TSO (Total Store Order): lebih kuat dari relaxed memory model tapi tidak sekuat sequential consistency. Store bisa di-buffer sebelum visible ke prosesor lain (store-load reordering diizinkan), tapi store ordering relatif antar prosesor konsisten. Programmer butuh memory barrier (MFENCE/SFENCE/LFENCE) untuk full ordering."},
  {"question":"Kondisi flag (Zero, Carry, Sign, Overflow) pada x86 di-update setelah operasi aritmatika untuk...","options":["Menentukan kecepatan eksekusi instruksi berikutnya","Memungkinkan conditional branch dan conditional move berdasarkan hasil operasi sebelumnya","Menyimpan carry dari operasi bit shifting","Menandai register yang telah dimodifikasi"],"answer":1,"difficulty":2,"explanation":"EFLAGS (x86): ZF (Zero Flag) = hasil nol; CF (Carry Flag) = carry/borrow unsigned; SF (Sign Flag) = hasil negatif; OF (Overflow Flag) = overflow signed. Instruksi CMP (compare) melakukan SUB tapi hanya update flags. JZ, JNE, JG, JL, dll. membaca flags ini untuk conditional branching."},
  {"question":"Floating point arithmetic menggunakan standar IEEE 754 untuk...","options":["Meningkatkan kecepatan komputasi integer","Merepresentasikan bilangan real dengan presisi terbatas menggunakan format sign-exponent-mantissa","Menggantikan semua operasi integer","Memudahkan konversi antara desimal dan biner"],"answer":1,"difficulty":2,"explanation":"IEEE 754 single precision (32-bit): 1 bit sign, 8 bit exponent (bias 127), 23 bit mantissa. Range: ±1.4×10^-45 to ±3.4×10^38. Double precision (64-bit): 1+11+52 bit. Standar ini menjamin hasil yang konsisten di berbagai platform. Memiliki representasi khusus: ±0, ±∞, NaN (Not a Number)."},
  {"question":"Teknik loop unrolling dalam compiler optimization mengubah loop untuk...","options":["Mengurangi jumlah iterasi dengan menambah kode instruksi dalam loop body","Menjalankan loop pada thread berbeda","Memindahkan loop ke cache khusus","Menghapus kondisi loop dari program"],"answer":0,"difficulty":3,"explanation":"Loop unrolling: meng-expand body loop N kali dalam satu iterasi, mengurangi branch overhead dan membuka peluang SIMD/ILP. For(i=0;i<100;i++) vs unroll 4x: For(i=0;i<100;i+=4){A[i];A[i+1];A[i+2];A[i+3]}. Trade-off: kode lebih besar (instruction cache pressure) vs performa loop lebih tinggi."},
  {"question":"Pada ISA MIPS, instruksi J (Jump) menggunakan 26-bit target address. Cara CPU menghitung alamat penuh 32-bit target adalah...","options":["Zero-extend 26 bit ke 32 bit","4 bit atas PC digabungkan dengan 26 bit target yang di-shift kiri 2 bit","Target di-sign-extend dari 26 ke 32 bit","Tambahkan offset 26 bit ke base register"],"answer":1,"difficulty":3,"explanation":"MIPS J-format: [opcode 6bit][target 26bit]. Alamat penuh = {PC[31:28], target[25:0], 00} — 4 bit atas dari PC dipertahankan (jump dalam region 256MB yang sama), 26 bit dishift kiri 2 (karena instruksi selalu word-aligned, 2 bit bawah selalu 00), total 32 bit. Untuk jump lintas region, gunakan JR (jump register) dengan alamat 32-bit penuh."},
  {"question":"Interrupts berbeda dari exceptions dalam arsitektur CPU karena...","options":["Interrupt lebih cepat diproses dari exception","Interrupt berasal dari device eksternal (asinkron terhadap instruksi), exception berasal dari eksekusi instruksi itu sendiri (sinkron)","Exception tidak bisa ditangani oleh OS","Interrupt hanya terjadi pada operasi I/O"],"answer":1,"difficulty":2,"explanation":"Interrupt (asinkron): sinyal dari hardware eksternal (timer, keyboard, NIC) — terjadi kapanpun, tidak terkait instruksi spesifik. Exception (sinkron): dipicu oleh instruksi itu sendiri — divide by zero, page fault, invalid opcode, system call. Keduanya menyebabkan CPU berpindah ke handler, bedanya di sumber dan timing."},
],
9: [
  {"question":"Pipeline stall (bubble) yang disebabkan oleh data hazard terjadi karena...","options":["CPU kehabisan instruksi untuk dieksekusi","Instruksi berikutnya membutuhkan hasil instruksi sebelumnya yang belum selesai dieksekusi","Dua instruksi mencoba menggunakan bus yang sama","Branch prediction meleset"],"answer":1,"difficulty":2,"explanation":"Data hazard RAW (Read After Write): instruksi I2 butuh output dari I1, tapi I1 belum selesai di stage sebelumnya. Tanpa forwarding: harus stall sampai I1 tulis ke register. Dengan forwarding: hasil dari stage EX/MEM I1 bisa langsung digunakan I2 tanpa tunggu writeback, mengurangi stall."},
  {"question":"Teknik forwarding (data bypassing) mengurangi pipeline stall dengan cara...","options":["Mempercepat clock CPU secara dinamis","Menyalurkan hasil dari stage pipeline yang lebih awal langsung ke stage yang membutuhkan, tanpa tunggu writeback","Menduplikasi unit eksekusi","Memprediksi nilai operand sebelum komputasi selesai"],"answer":1,"difficulty":2,"explanation":"Forwarding: tambahkan multiplexer dan path langsung antara stage. EX-to-EX forwarding: hasil ALU stage N bisa langsung digunakan stage N+1 tanpa tunggu Write Back (2 cycle kemudian). MEM-to-EX forwarding untuk load result. Forwarding menghilangkan sebagian besar data hazard stall kecuali load-use hazard."},
  {"question":"2-bit saturating counter pada branch predictor menyimpan 4 state untuk...","options":["Memprediksi dua branch sekaligus","Mencegah satu misprediction langsung mengubah prediksi, membutuhkan dua misprediction berturut-turut untuk ganti arah","Menyimpan alamat target branch","Menghitung berapa kali branch diambil"],"answer":1,"difficulty":3,"explanation":"2-bit counter states: Strongly Taken, Weakly Taken, Weakly Not-Taken, Strongly Not-Taken. Loop 'if(x) goto top' yang biasanya taken: berada di Strongly Taken. Satu not-taken (akhir loop) → Weakly Taken, tapi prediksi masih Taken. Loop butuh 2 not-taken berturut-turut untuk flip prediksi — ini ideal karena loop biasanya taken hampir setiap kali."},
  {"question":"Tomasulo's Algorithm mengatasi data hazard dan WAW/WAR hazard menggunakan...","options":["Penambahan pipeline stage khusus","Register renaming via reservation stations yang melacak operand dan hasil secara dinamis","Prediksi nilai operand","Duplikasi register file"],"answer":1,"difficulty":3,"explanation":"Tomasulo (IBM 360/91, 1967): reservation station menyimpan instruksi + operand yang belum ready. Saat operand tersedia (via Common Data Bus), instruksi dispatch ke unit eksekusi. Register renaming implisit melalui reservation station tags menghilangkan WAR dan WAW hazard. Dasar dari out-of-order execution modern."},
  {"question":"Precise exception dalam CPU pipelined berarti...","options":["Hanya exception yang bisa diprediksi yang ditangani","CPU dapat memastikan semua instruksi sebelum yang menyebabkan exception sudah selesai, dan instruksi setelahnya dibatalkan dengan benar","Exception terjadi tepat saat instruksi di-fetch","Semua exception diproses dengan latency yang sama"],"answer":1,"difficulty":3,"explanation":"Precise exception: CPU harus bisa 'membekukan' state tepat pada instruksi yang menyebabkan exception. Program counter menunjuk instruksi faulting, semua instruksi sebelumnya sudah committed, instruksi setelahnya belum. Diperlukan untuk: page fault (restart instruksi), debugging, dan interrupt handling yang benar. Reorder Buffer (ROB) memastikan commit in-order."},
  {"question":"Speculative execution menyebabkan kerentanan Spectre karena...","options":["CPU tidak memverifikasi izin akses memori","CPU mengeksekusi instruksi spekulatif yang mungkin melewati batas keamanan, meninggalkan jejak di side channel (cache timing)","Spekulasi membocorkan data ke register yang bisa dibaca proses lain","Out-of-order execution tidak mengikuti privilege level"],"answer":1,"difficulty":3,"explanation":"Spectre: CPU spekulatif mengeksekusi kode di luar bounds check yang belum di-evaluasi. Akses memori spekulatif ke data privileged mengisi cache. Meski instruksi di-squash (karena missprediksi/pelanggaran keamanan), efek cache tidak di-rollback. Attacker mengukur waktu akses cache (Flush+Reload) untuk deduksi data. Patch memerlukan perubahan ISA dan OS."},
  {"question":"Metode pengurangan branch penalty 'branch delay slot' berbeda dari 'branch prediction' karena...","options":["Delay slot lebih akurat dari prediksi","Delay slot always mengeksekusi instruksi setelah branch terlepas branch diambil, prediksi mencoba menebak arah branch","Prediksi menggunakan lebih banyak hardware dari delay slot","Delay slot hanya tersedia untuk conditional branch"],"answer":1,"difficulty":2,"explanation":"Branch delay slot (arsitektur awal RISC): instruksi tepat setelah branch selalu dieksekusi — compiler mengisi dengan instruksi yang berguna dalam semua kasus. Deterministic tapi compiler harus sadar. Branch prediction: hardware menebak arah, mulai fetch spekulatif, squash jika salah. Prediction lebih efektif untuk pipeline dalam tapi memerlukan hardware kompleks."},
  {"question":"Hyper-Threading (SMT — Simultaneous Multi-Threading) pada Intel CPU bekerja dengan cara...","options":["Membagi CPU secara fisik menjadi dua prosesor independen","Menyimpan dua set architectural state (register, PC) dalam satu core fisik untuk mengisi slot pipeline yang idle","Menjalankan dua program pada kecepatan setengahnya masing-masing","Meningkatkan clock speed saat ada dua thread aktif"],"answer":1,"difficulty":3,"explanation":"SMT/HT: satu core fisik punya 2 (atau lebih) set lengkap architectural state (register file, PC, EFLAGS). Dua thread berjalan 'secara bersamaan' — saat thread 1 stall (cache miss, load latency), thread 2 menggunakan execution units yang idle. Resource sharing: ALU, FPU, cache, TLB dibagi. Overhead area chip kecil (~5%) tapi throughput naik 15-30% untuk mixed workload."},
  {"question":"Control hazard pada pipeline RISC sederhana (tanpa prediksi) menyebabkan wasted cycles karena...","options":["Control unit terlalu lambat untuk menghasilkan sinyal kontrol","CPU tidak tahu instruksi mana yang harus di-fetch berikutnya sampai branch di-execute (setelah stage EX)","Memory terlalu lambat untuk fetch instruksi","ALU tidak bisa memproses instruksi branch"],"answer":1,"difficulty":2,"explanation":"Pada RISC 5-stage (IF, ID, EX, MEM, WB): branch decision diketahui di akhir stage EX (cycle ke-3). Sementara itu, 2 instruksi berikutnya sudah di-fetch dan di-decode — harus di-squash jika branch diambil (2-cycle penalty). Static prediction (assume not-taken) mengurangi penalty tapi tidak menghilangkan."},
  {"question":"Microprogrammed control unit menyimpan sinyal kontrol dalam...","options":["Hardware logic gates yang di-hardwire","Read-only memory (control store) sebagai sequence of microinstructions","Register file khusus untuk kontrol","Cache khusus untuk sinyal kontrol"],"answer":1,"difficulty":2,"explanation":"Microprogrammed CU: setiap instruksi mesin dipetakan ke sequence microinstruction dalam control store (ROM). Lebih mudah diimplementasikan dan dimodifikasi (bug fix via microcode update), tapi lebih lambat dari hardwired. x86 CPU modern menggunakan kombinasi: instruksi sederhana (hardwired fast path) + instruksi kompleks (microcode sequencer)."},
  {"question":"Instruction-level parallelism (ILP) dibatasi oleh...","options":["Kecepatan memori cache","True data dependencies (RAW) antar instruksi yang tidak bisa dihilangkan","Ukuran register file","Kecepatan bus data"],"answer":1,"difficulty":3,"explanation":"ILP: eksekusi instruksi-instruksi independen secara paralel. Dibatasi oleh: (1) RAW (true dependency) — tidak bisa dieleminasi, harus tunggu; (2) WAR dan WAW (false dependency) — bisa dihilangkan dengan register renaming; (3) Control dependency (branch); (4) Memory dependency (load-store aliasing). Studi Rau dan Fisher menunjukkan rata-rata ILP program ~3-5."},
  {"question":"Store buffer (store queue) pada CPU out-of-order digunakan untuk...","options":["Menyimpan instruksi store yang menunggu untuk dieksekusi","Menampung hasil store yang sudah dieksekusi speculative tapi belum committed ke cache/memori","Buffer untuk instruksi yang datang dari memory controller","Menyimpan alamat yang sering diakses oleh store"],"answer":1,"difficulty":3,"explanation":"Store buffer: instruksi store yang sudah di-execute di-simpan sementara sambil menunggu commit (instruksi harus retire in-order). Manfaat: (1) Decoupling eksekusi dari cache write, (2) Subsequent load dari alamat sama bisa langsung forward dari store buffer tanpa akses cache (store-to-load forwarding). Di-flush ke cache saat commit."},
  {"question":"Branch Target Buffer (BTB) menyimpan...","options":["Hasil prediksi (taken/not-taken) untuk setiap branch","Alamat target dari instruksi branch yang pernah dieksekusi","Register yang digunakan oleh instruksi branch","History semua branch yang pernah mispredicted"],"answer":1,"difficulty":3,"explanation":"BTB: cache kecil (256-4096 entry) yang memetakan alamat instruksi branch → alamat target. Saat CPU fetch instruksi, jika alamat ada di BTB, langsung fetch dari target (tanpa decode branch dulu). Dikombinasikan dengan predictor (BHT), memungkinkan prediksi penuh dalam satu cycle sebelum instruksi bahkan di-decode."},
  {"question":"Pada ARM Cortex-A series, TrustZone menyediakan...","options":["Virtualisasi hardware untuk beberapa OS","Lingkungan eksekusi terpercaya (Secure World) yang terisolasi dari Normal World via hardware boundary","Proteksi memori berbasis enkripsi untuk setiap proses","Cache partitioning untuk mencegah side-channel attack"],"answer":1,"difficulty":3,"explanation":"ARM TrustZone: CPU bisa beroperasi dalam dua state — Secure World (TEE: Trusted Execution Environment) dan Normal World (Android/Linux). Transisi via monitor mode (EL3). Secure World punya akses ke memori tertentu yang tidak bisa diakses Normal World meski kernel compromised. Digunakan untuk: fingerprint processing, DRM, mobile payment."},
  {"question":"Physical Register File (PRF) architecture berbeda dari architectural register file karena...","options":["PRF lebih kecil dari architectural register file","PRF jauh lebih besar — menyimpan semua in-flight values dari instruksi yang belum commit, mendukung register renaming out-of-order","PRF menggunakan SRAM yang lebih cepat","PRF diakses melalui cache tersendiri"],"answer":1,"difficulty":3,"explanation":"PRF: pool besar register fisik (misalnya 180 register pada Intel Skylake, vs 16 logical register x86-64). Rename table memetakan logical register → physical register. Setiap instruksi yang tulis alokasi physical register baru — menghilangkan WAR/WAW hazard. Physical register di-free saat instruksi yang memegang nilainya retire."},
  {"question":"Scoreboard algorithm pada CDC 6600 mengatasi data hazard dengan cara...","options":["Menambahkan delay slot setelah setiap instruksi","Melacak status setiap functional unit dan register, menahan instruksi jika dependency belum siap","Menduplikasi semua functional unit","Mengeksekusi semua instruksi secara serial"],"answer":1,"difficulty":3,"explanation":"Scoreboard (CDC 6600, 1964): centralized control yang melacak: (1) Functional unit status (busy/free), (2) Instruction status (per stage), (3) Register result status (unit mana yang akan tulis register X). Instruksi stall jika dependency belum ready. Lebih primitif dari Tomasulo tapi tidak rename register — masih bisa stall karena WAR/WAW."},
  {"question":"Reservation Station (RS) pada Tomasulo's Algorithm berbeda dari simple instruction queue karena...","options":["RS bisa menyimpan lebih banyak instruksi","RS menyimpan operand secara inline sehingga instruksi bisa dispatch begitu operand tersedia, tanpa perlu akses register file kembali","RS digunakan hanya untuk floating point operations","RS adalah nama lain untuk reorder buffer"],"answer":1,"difficulty":3,"explanation":"RS: setiap entry menyimpan operand yang sudah tersedia atau tag untuk operand yang belum ready. Saat operand broadcast di Common Data Bus (CDB), semua RS yang menunggu tag tersebut langsung capture nilai — tidak perlu akses register file lagi. Instruksi dispatch ke execution unit segera saat semua operand siap, tanpa koordinasi central scoreboard."},
  {"question":"Prediksi cabang TAGE (Tagged Geometric History Length) unggul dibanding perceptron predictor karena...","options":["TAGE menggunakan neural network yang lebih kompleks","TAGE menggunakan multiple prediction tables dengan history length geometris, menangkap korelasi branch dengan history panjang maupun pendek","TAGE lebih murah dari segi hardware","TAGE tidak memerlukan training"],"answer":1,"difficulty":3,"explanation":"TAGE (Seznec & Michaud 2006): beberapa predictor table dengan history length geometris (L, 2L, 4L, 8L, ...). Provider dengan history terpanjang yang match digunakan. Jika tidak ada provider panjang yang match, fallback ke bimodal. Menangkap korelasi di berbagai granularitas history. MISPB rate < 3% pada SPEC CPU2006 — state-of-art untuk hardware branch prediction."},
  {"question":"Heat dissipation (thermal design power) membatasi frekuensi CPU karena...","options":["Komponen elektronik mencair pada suhu tinggi","Power ∝ C × V² × f — meningkatkan frekuensi secara linear meningkatkan power secara linear, yang menghasilkan panas proporsional","Pendingin tidak bisa berfungsi di frekuensi tinggi","Memori tidak bisa sinkronisasi dengan CPU frekuensi tinggi"],"answer":1,"difficulty":3,"explanation":"Dynamic power = C × V² × f (C = kapasitansi, V = voltase, f = frekuensi). Meningkatkan f 2x → power 2x → suhu 2x (tanpa voltase naik). Dennard Scaling (menurunkan V saat shrink node) mulai gagal ~2005: sulit turunkan voltase lebih jauh tanpa meningkatkan leakage current. Sejak saat itu, industri beralih ke multi-core daripada menaikkan frekuensi single core."},
  {"question":"Reorder Buffer (ROB) memungkinkan CPU out-of-order untuk...","options":["Menjalankan instruksi lebih cepat dari clock cycle","Mengeksekusi instruksi keluar dari urutan program tapi commit hasilnya ke architectural state secara in-order, memastikan precise exception","Menyimpan instruksi yang gagal di-decode","Menggandakan jumlah register yang tersedia"],"answer":1,"difficulty":3,"explanation":"ROB: circular buffer yang menyimpan semua in-flight instruksi dalam program order. Head = instruksi tertua (siap commit), Tail = instruksi terbaru. Instruksi di-execute out-of-order tapi hanya commit (tulis ke architectural state) saat berada di HEAD dan sudah selesai. Jika exception: semua instruksi lebih muda di-squash, state precise pada titik exception."},
],
10: [
  {"question":"Kondisi Bernstein untuk menentukan apakah dua instruksi bisa dieksekusi paralel memeriksa...","options":["Apakah kedua instruksi menggunakan unit eksekusi yang sama","Tidak ada read-write, write-read, atau write-write dependency antara set input/output keduanya","Apakah kedua instruksi memiliki panjang yang sama","Apakah kedua instruksi mengakses cache yang sama"],"answer":1,"difficulty":3,"explanation":"Bernstein conditions (1966): instruksi I1 dan I2 bisa paralel jika: (1) Output(I1) ∩ Input(I2) = ∅ (no RAW), (2) Input(I1) ∩ Output(I2) = ∅ (no WAR), (3) Output(I1) ∩ Output(I2) = ∅ (no WAW). Dasar teoritis untuk compiler parallelization dan hardware out-of-order execution."},
  {"question":"RISC architecture mengurangi Cycles Per Instruction (CPI) dengan cara...","options":["Menggunakan instruksi yang lebih kompleks untuk mengurangi jumlah instruksi","Menyederhanakan instruksi sehingga hampir semua bisa selesai dalam satu cycle pipeline stage","Meningkatkan frekuensi clock CPU","Menggunakan cache yang lebih besar"],"answer":1,"difficulty":2,"explanation":"RISC: instruksi sederhana, format fixed, load-store, banyak register → pipeline stages pendek dan seragam → CPI mendekati 1 (dengan pipeline). CISC: instruksi kompleks bisa butuh banyak cycle → CPI > 1 untuk banyak instruksi. Modern x86 mendekati RISC di level micro-ops (decode CISC → RISC-like micro-ops internal)."},
  {"question":"Amdahl's Law: jika 80% program bisa diparalelkan, speedup maksimal dengan prosesor tak terbatas adalah...","options":["Tidak terbatas","5x","80x","2x"],"answer":1,"difficulty":2,"explanation":"Amdahl: Speedup_max = 1 / (1 - P) di mana P = fraksi yang bisa diparalelkan. P = 0.8: Speedup = 1 / (1 - 0.8) = 1 / 0.2 = 5x. Serial portion 20% menjadi bottleneck. Dengan 10 prosesor: 1 / (0.2 + 0.8/10) = 1/0.28 = 3.57x. Implikasi: bahkan dengan prosesor tak terbatas, serial part membatasi speedup ke 5x."},
  {"question":"NUMA (Non-Uniform Memory Access) terjadi dalam sistem multiprocessor karena...","options":["Semua prosesor berbagi satu chip memori yang sama","Prosesor yang berbeda memiliki latensi berbeda ke bagian memori yang berbeda — memori lokal lebih cepat dari memori remote","NUMA hanya digunakan dalam superkomputer","Prosesor tidak bisa berbagi memori sama sekali dalam NUMA"],"answer":1,"difficulty":2,"explanation":"NUMA: dalam server multi-socket, setiap socket CPU punya memory controller sendiri dan DIMM lokalnya. Akses memori lokal: ~50-80ns. Akses memori di socket lain via QPI/UPI interconnect: ~150-300ns (2-4x lebih lambat). OS NUMA-aware alokasikan memori di node yang sama dengan thread untuk meminimalkan remote access."},
  {"question":"Gustafson's Law (Gustafson-Barsis Law) memberikan pandangan berbeda dari Amdahl dengan argumen bahwa...","options":["Parallelisme tidak memberikan speedup nyata","Ukuran problem yang diselesaikan biasanya meningkat seiring jumlah prosesor, sehingga bagian serial tetap kecil secara relatif","Semua program bisa diparalelkan 100%","Amdahl's Law hanya valid untuk 2 prosesor"],"answer":1,"difficulty":3,"explanation":"Gustafson (1988): Amdahl mengasumsikan problem size tetap. Kenyataannya, lebih banyak prosesor digunakan untuk solve problem LEBIH BESAR dalam waktu yang sama. Serial fraction relatif mengecil. Scaled speedup = N - s(N-1) di mana s = serial fraction, N = prosesor. Lebih optimistis dari Amdahl untuk workload scientific yang scalable."},
  {"question":"Snooping cache coherence protocol bekerja dengan cara...","options":["Central directory mencatat lokasi setiap cache line","Setiap cache memonitor semua transaksi bus untuk mendeteksi jika ada cache lain yang mengakses line yang dimilikinya","Hanya satu prosesor yang bisa memegang cache line pada satu waktu","Cache coherence diserahkan kepada software (OS)"],"answer":1,"difficulty":3,"explanation":"Bus snooping: semua cache terhubung ke shared bus. Setiap cache 'mendengarkan' semua operasi read/write di bus. Jika cache A memegang line X dan melihat cache B menulis ke X di bus → invalidate copy-nya. Sederhana dan efektif untuk jumlah prosesor kecil (<~16). Untuk jumlah besar, bus menjadi bottleneck → gunakan directory protocol."},
  {"question":"Synchronization primitive 'compare-and-swap' (CAS) digunakan dalam lock-free programming karena...","options":["CAS lebih cepat dari mutex dalam semua kondisi","CAS secara atomik memeriksa nilai dan mengupdate hanya jika nilai masih sama dengan expected — memungkinkan algoritma non-blocking","CAS tidak memerlukan hardware khusus","CAS menghilangkan kebutuhan cache coherency"],"answer":1,"difficulty":3,"explanation":"CAS(addr, expected, new): atomik — compare *addr dengan expected, jika sama, set *addr = new dan return true. Jika tidak sama, return false (nilai sudah berubah oleh thread lain). Digunakan untuk: atomic counter, lock-free stack/queue, read-copy-update (RCU). Hardware: x86 CMPXCHG, ARM LDREX/STREX, Java AtomicInteger."},
  {"question":"Data parallelism berbeda dari task parallelism dalam cara kerja berikut...","options":["Data parallelism lebih mudah diimplementasikan","Data parallelism: operasi yang sama diaplikasikan ke banyak data (SIMD/GPU); task parallelism: tugas berbeda dieksekusi secara bersamaan (pipeline, thread pool)","Task parallelism tidak memerlukan sinkronisasi","Data parallelism hanya bekerja pada array"],"answer":1,"difficulty":2,"explanation":"Data parallelism: array[0..N] += scalar — tiap core proses subset data dengan operasi identik. Ideal untuk GPU (ribuan core SIMD). Task parallelism: producer-consumer pipeline, web server (tiap request = task berbeda). Banyak program hybrid — OpenMP mendukung keduanya: parallel sections (task) dan parallel for (data)."},
  {"question":"Memory consistency model Sequential Consistency (SC) mendefinisikan...","options":["Semua akses memori terjadi dalam urutan clock cycle","Hasil eksekusi parallel sama seolah semua operasi semua processor dieksekusi dalam urutan sequential tertentu, dan operasi tiap processor mempertahankan urutan program","SC memerlukan cache yang disabled","Sequential Consistency hanya untuk single-core CPU"],"answer":1,"difficulty":3,"explanation":"SC (Lamport 1979): model paling intuitif — programmer bisa berasumsi ada total order global dari semua operasi memori. Tapi hardware modern (store buffer, out-of-order) melanggar SC untuk performa. x86 menggunakan TSO (Total Store Order) — lebih relaxed. Java/C++ memory model lebih relaxed lagi. Programmer butuh explicit barriers untuk stronger ordering."},
  {"question":"MPI (Message Passing Interface) vs OpenMP: perbedaan fundamental model komputasinya adalah...","options":["MPI hanya untuk superkomputer, OpenMP untuk desktop","MPI: distributed memory (proses berkomunikasi via explicit message), OpenMP: shared memory (thread berbagi memori, sinkronisasi via barrier/lock)","OpenMP lebih cepat dari MPI dalam semua kondisi","MPI tidak bisa digunakan bersamaan dengan OpenMP"],"answer":1,"difficulty":2,"explanation":"MPI: proses-proses independent dengan memori terpisah — komunikasi via MPI_Send/MPI_Recv, MPI_Bcast, dll. Scalable ke ribuan node cluster. OpenMP: thread dalam satu node berbagi address space — parallelisasi mudah dengan pragma, tapi terbatas dalam satu node. Hybrid MPI+OpenMP: MPI antar node, OpenMP dalam node — paling efisien untuk HPC cluster."},
  {"question":"Warp divergence pada GPU CUDA terjadi ketika...","options":["GPU kehabisan memory bandwidth","Thread dalam satu warp mengeksekusi path kode berbeda akibat conditional branch, menyebabkan beberapa thread idle sementara path lain dieksekusi","Dua warp mencoba mengakses memori yang sama","Kernel GPU dipanggil terlalu sering"],"answer":1,"difficulty":3,"explanation":"Warp (NVIDIA): 32 thread yang dieksekusi SIMT (Single Instruction Multiple Thread). Jika ada if-else dalam kernel: GPU mengeksekusi kedua path secara serial (bukan paralel) — thread yang 'salah path' di-mask/disabled. Worst case: 32 thread, 32 path berbeda → 32x serialization. Minimasi divergence adalah kunci optimasi GPU kernel."},
  {"question":"Cache coherency protocol MOESI menambahkan state 'Owned' untuk...","options":["Menandai cache line yang dimiliki oleh OS","Memungkinkan transfer cache line antar prosesor tanpa harus menulis ke memori utama terlebih dahulu","Menandai cache line yang sedang di-prefetch","State untuk cache line yang sedang dienkripsi"],"answer":1,"difficulty":3,"explanation":"MOESI states: M(odified), O(wned), E(xclusive), S(hared), I(nvalid). State O: prosesor punya copy dirty yang harus diberikan ke prosesor lain yang meminta (memori out-of-date), tapi tidak perlu writeback ke memori dulu. O berbeda dari M: copy O boleh ada di prosesor lain (Shared). Mengurangi memory traffic dibanding MESI yang harus writeback sebelum share."},
  {"question":"Vectorization dalam compiler mengkonversi scalar loop menjadi instruksi SIMD ketika...","options":["Loop selalu memiliki jumlah iterasi yang bisa dibagi 4","Tidak ada data dependency antar iterasi loop (loop-carried dependency) dan akses memori bersifat sequential/stride-1","Compiler mendapat hint dari programmer via pragma","Loop hanya mengandung operasi integer"],"answer":1,"difficulty":3,"explanation":"Auto-vectorization: compiler analisis loop untuk: (1) Independence — tiap iterasi tidak bergantung pada iterasi lain; (2) Aligned, contiguous memory access (stride-1 ideal, stride-2 bisa tapi kurang efisien); (3) Tidak ada alias (pointer analysis). Jika semua terpenuhi: scalar loop → SIMD (SSE/AVX). Programmer bisa bantu dengan restrict pointer, aligned_alloc."},
  {"question":"Heterogeneous computing (CPU + GPU + FPGA) dalam satu sistem digunakan karena...","options":["Satu jenis prosesor tidak cukup powerful","Setiap compute unit dioptimalkan untuk jenis workload berbeda — CPU untuk serial/OS, GPU untuk data-parallel, FPGA untuk fixed-function latency-critical","Regulasi hardware mengharuskan penggunaan semua jenis prosesor","GPU lebih murah dari CPU sehingga digunakan untuk task ringan"],"answer":1,"difficulty":3,"explanation":"Heterogeneous: CPU — general purpose, low-latency serial tasks, OS kernel, branch-heavy code. GPU — high throughput data-parallel (ML training, raytracing, physics simulation). FPGA — custom pipeline dengan latensi sangat rendah dan deterministik (network packet processing, HFT trading, SDR). Workload dibagi ke unit paling efisien."},
  {"question":"Transactional Memory (HTM — Hardware Transactional Memory) seperti Intel TSX menyederhanakan synchronization dengan cara...","options":["Menghilangkan kebutuhan cache dalam program paralel","Memungkinkan programmer menandai 'region transaksional' yang dieksekusi atomik — hardware otomatis mendeteksi konflik dan retry","Mempercepat semua operasi memori 2x","Menggantikan semua lock dengan cas operation"],"answer":1,"difficulty":3,"explanation":"HTM: XBEGIN...XEND mendefinisikan transaksi. Hardware melacak read/write set. Jika tidak ada konflik dengan transaksi lain saat commit → sukses atomik. Jika konflik → abort dan retry. Programmer tidak perlu tulis lock/unlock — lebih mudah dan sering lebih cepat dari lock-based karena tidak ada lock contention untuk transaksi yang tidak bertabrakan."},
  {"question":"Flynn's SIMD (Single Instruction Multiple Data) pada level CPU berbeda dari GPU SIMT karena...","options":["SIMD hanya untuk CPU, SIMT hanya untuk GPU","SIMD: semua lane harus mengeksekusi instruksi identik tanpa divergence; SIMT: thread individual dalam warp bisa diverge (tapi dengan serialization penalty)","SIMT lebih cepat dari SIMD dalam semua kondisi","SIMD mendukung floating point, SIMT tidak"],"answer":1,"difficulty":3,"explanation":"SIMD (CPU — SSE/AVX): 4-16 lane strict lockstep, tidak ada notion of divergence — semua lane eksekusi instruksi yang sama pada data berbeda. SIMT (GPU): 32 thread per warp tampak independen dari sudut pandang programmer, tapi hardware eksekusi dalam lockstep — jika diverge, serialisasi terjadi. SIMT lebih programmer-friendly tapi divergence penalty harus dipahami."},
  {"question":"Scalable coherent interconnect (seperti Intel UPI, AMD Infinity Fabric) pada server multi-socket dirancang untuk...","options":["Menggantikan PCIe untuk GPU connection","Menghubungkan multiple CPU socket dengan bandwidth tinggi dan latensi rendah untuk mendukung cache coherency antar socket","Menghubungkan DRAM langsung ke GPU","Menyediakan interface debugging untuk hardware engineer"],"answer":1,"difficulty":3,"explanation":"UPI/Infinity Fabric: point-to-point interconnect antara CPU sockets. Mendukung: (1) Cache coherency antar socket (MESIF protocol messages), (2) Memory access remote (NUMA), (3) Bandwidth tinggi (UPI 3.0: ~41.6 GB/s per direction). Menggantikan FSB (Front Side Bus) yang menjadi bottleneck — setiap CPU punya direct link ke socket lain."},
  {"question":"GPGPU computing menggunakan GPU untuk komputasi umum (bukan grafis) karena GPU memiliki...","options":["Kecepatan clock yang lebih tinggi dari CPU","Ribuan core sederhana yang optimal untuk throughput-oriented workload dengan banyak data paralel","Kapasitas cache yang lebih besar dari CPU","Kemampuan menjalankan sistem operasi sendiri"],"answer":1,"difficulty":2,"explanation":"GPU vs CPU arsitektur filosofi berbeda: CPU — sedikit core (8-64) yang sangat powerful, optimasi untuk single-thread latency, banyak cache. GPU — ribuan core sederhana (4000-16000 CUDA cores), throughput-oriented, lebih sedikit cache per core, high-bandwidth memory (HBM). Ideal untuk: matrix multiplication (ML), Monte Carlo simulation, FFT, rendering."},
  {"question":"Load balancing dalam sistem multiprocessor bertujuan untuk...","options":["Menyeimbangkan voltase antar prosesor","Mendistribusikan workload secara merata antar prosesor sehingga tidak ada yang idle sementara yang lain overloaded","Mengoptimalkan penggunaan cache di setiap prosesor","Memastikan semua prosesor mengakses memori dengan kecepatan yang sama"],"answer":1,"difficulty":2,"explanation":"Load imbalance: jika P1 dapat 90% pekerjaan dan P2 hanya 10%, total waktu = waktu P1 (P2 idle menunggu). Efisiensi turun drastis. Solusi: (1) Static: bagi tugas merata dari awal (cocok jika beban per tugas seragam); (2) Dynamic: work stealing (thread idle mencuri task dari thread sibuk — digunakan Java ForkJoin, OpenMP dynamic schedule). Dynamic lebih adaptif tapi overhead lebih besar."},
  {"question":"Konsep 'embarrassingly parallel' (pleasingly parallel) merujuk pada masalah yang...","options":["Sangat sulit untuk diparalelkan","Bisa dibagi menjadi submasalah independen tanpa komunikasi antar prosesor, sehingga efisiensi paralel mendekati 100%","Memerlukan sinkronisasi setiap cycle","Hanya bisa dijalankan pada GPU"],"answer":1,"difficulty":2,"explanation":"Embarrassingly parallel: setiap sub-task benar-benar independent — tidak ada shared state, tidak ada komunikasi. Contoh: rendering frame video (tiap frame independent), Monte Carlo simulation (tiap sample independent), brute force password cracking, parameter sweep dalam eksperimen scientific. Speedup linier dengan jumlah prosesor — Amdahl's s≈0, speedup ≈ N."},
]
};

for (let lvl = 6; lvl <= 10; lvl++) {
  const levelObj = quizzes.levels.find(l => l.id === lvl);
  if (levelObj) {
    const existingQuestions = new Set(levelObj.questions.map(q => q.question));
    for (const q of NEW_QUESTIONS[lvl]) {
      if (!existingQuestions.has(q.question)) {
        levelObj.questions.push(q);
      }
    }
  }
}

let totalQuestions = 0;
quizzes.levels.forEach(l => {
  totalQuestions += l.questions.length;
});

fs.writeFileSync(quizzesPath, JSON.stringify(quizzes, null, 2), 'utf8');
console.log('Quizzes updated successfully! Total questions now:', totalQuestions);
